const docs = ($input.first().json.documents) || [];

if (docs.length === 0) {
  return [{ json: { output: 'No hay coleadores inscritos todavía, así que no se puede generar el sorteo.' } }];
}

// Fisher-Yates, igual que generarSorteoInicial() en script.js
const shuffled = [...docs];
for (let i = shuffled.length - 1; i > 0; i--) {
  const j = Math.floor(Math.random() * (i + 1));
  [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
}

const puestoNombres = ['1 (Coso)', '2 (Centro)', '3 (Tapón)', '4 (Puerta)'];
let texto = '🎲 Sorteo rápido (no oficial, solo referencial vía bot):\n\n';

for (let i = 0; i < shuffled.length; i += 4) {
  const turnoNum = Math.floor(i / 4) + 1;
  const grupo = shuffled.slice(i, i + 4);
  texto += `TURNO ${turnoNum}\n`;
  grupo.forEach((d, idx) => {
    const f = d.fields || {};
    const nombre = (f.nombre && f.nombre.stringValue) || '—';
    const equino = (f.equino && f.equino.stringValue) || '—';
    texto += `  ${puestoNombres[idx]}: ${nombre} — ${equino}\n`;
  });
  texto += '\n';
}

texto += 'Nota: este sorteo es una simulación rápida generada por el bot y no reemplaza ni bloquea el sorteo oficial dentro del sistema SGC FEVECO.';

return [{ json: { output: texto.trim() } }];
